auto canMergeSelectThroughBinop = [](BinaryOperator *BO) {
  // The select might be preventing a division by 0.
  switch (BO->getOpcode()) {
  default:
    return true;
  case Instruction::SRem:
  case Instruction::URem:
  case Instruction::SDiv:
  case Instruction::UDiv:
    return false;
  }
};

// Try to simplify a binop sandwiched between 2 selects with the same
// condition.
// select(C, binop(select(C, X, Y), W), Z) -> select(C, binop(X, W), Z)
BinaryOperator *TrueBO;
if (match(TrueVal, m_OneUse(m_BinOp(TrueBO))) &&
    canMergeSelectThroughBinop(TrueBO)) {
  if (auto *TrueBOSI = dyn_cast<SelectInst>(TrueBO->getOperand(0))) {
    if (TrueBOSI->getCondition() == CondVal) {
      replaceOperand(*TrueBO, 0, TrueBOSI->getTrueValue());
      Worklist.push(TrueBO);
      return &SI;
    }
  }
  if (auto *TrueBOSI = dyn_cast<SelectInst>(TrueBO->getOperand(1))) {
    if (TrueBOSI->getCondition() == CondVal) {
      replaceOperand(*TrueBO, 1, TrueBOSI->getTrueValue());
      Worklist.push(TrueBO);
      return &SI;
    }
  }
}

// select(C, Z, binop(select(C, X, Y), W)) -> select(C, Z, binop(Y, W))
BinaryOperator *FalseBO;
if (match(FalseVal, m_OneUse(m_BinOp(FalseBO))) &&
    canMergeSelectThroughBinop(FalseBO)) {
  if (auto *FalseBOSI = dyn_cast<SelectInst>(FalseBO->getOperand(0))) {
    if (FalseBOSI->getCondition() == CondVal) {
      replaceOperand(*FalseBO, 0, FalseBOSI->getFalseValue());
      Worklist.push(FalseBO);
      return &SI;
    }
  }

  }
}

// select (select C, A, false), X, (select C, Y, Z) -> select C, (select A, X, Y), Z
// select (select C, A, false), (select C, Y, Z), X -> select C, (select A, Y, Z), X
// select (select C, true, A), (select C, Y, Z), X -> select C, Y, (select A, Z, X)
if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
  if (CondSI->getType()->isIntOrIntVectorTy(1)) {
    Value *C = CondSI->getCondition();
    errs() << "DEBUG: CondSI cond=" << *C << " true=" << *CondSI->getTrueValue() << " false=" << *CondSI->getFalseValue() << "\n";
    // Handle AND form: select C, A, false
    if (match(CondSI->getFalseValue(), m_Zero())) {
      Value *A = CondSI->getTrueValue();
      if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
        if (FalseSI->getCondition() == C &&
            !(!CondSI->hasOneUse() && !FalseSI->hasOneUse())) {
          Value *X = TrueVal;
          Value *Y = FalseSI->getTrueValue();
          Value *Z = FalseSI->getFalseValue();
          Value *InnerSel = Builder.CreateSelect(A, X, Y);
          return SelectInst::Create(C, InnerSel, Z);
        }
      }
      if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
        if (TrueSI->getCondition() == C &&
            !(!CondSI->hasOneUse() && !TrueSI->hasOneUse())) {
          Value *X = FalseVal;
          Value *Y = TrueSI->getTrueValue();
          Value *Z = TrueSI->getFalseValue();
          Value *InnerSel = Builder.CreateSelect(A, Y, Z);
          return SelectInst::Create(C, InnerSel, X);
        }
      }
    }
    // Handle OR form: select C, true, A
    if (match(CondSI->getTrueValue(), m_One())) {
      Value *A = CondSI->getFalseValue();
      if (auto *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
        if (TrueSI->getCondition() == C &&
            !(!CondSI->hasOneUse() && !TrueSI->hasOneUse())) {
          Value *X = FalseVal;
          Value *Y = TrueSI->getTrueValue();
          Value *Z = TrueSI->getFalseValue();
          Value *InnerSel = Builder.CreateSelect(A, Z, X);
          return SelectInst::Create(C, Y, InnerSel);
        }
      }
    }
  }
}

